CONCURRENCY = 100  # 并发数
TOTAL_REQUESTS = 1000  # 总请求数

def send_request(i):
    try:
        response = requests.post(URL, data=PAYLOAD, headers=HEADERS, timeout=5)
        print(f"[{i}] Status: {response.status_code}, Time: {response.elapsed.total_seconds()}s")
        return response.status_code
    except Exception as e:
        print(f"[{i}] Error: {e}")
        return None

# 并发发送
def main():
    start_time = time.time()
    with concurrent.futures.ThreadPoolExecutor(max_workers=CONCURRENCY) as executor:
        futures = [executor.submit(send_request, i) for i in range(TOTAL_REQUESTS)]
        results = [f.result() for f in concurrent.futures.as_completed(futures)]

    print(f"\n✅ Done. Sent {TOTAL_REQUESTS} requests in {time.time() - start_time:.2f} seconds.")
    success = sum(1 for r in results if r == 200)
    print(f"✅ Success: {success}, ❌ Failed: {TOTAL_REQUESTS - success}")

if __name__ == "__main__":
    print(time.time())
